// // This module implements an 8-bit binary down/up counter with synchronous reset. It decrements its value on every positive edge of the clock signal if the up_down signal is high, and increments if the up_down signal is low. The counter resets to 8'b00000000 on a positive edge of the reset signal.
module up_down_counter(
    input        clk,
    input        reset,
    input        up_down,
    output reg [7:0] count
);

// Counter logic
always @(posedge clk or posedge reset) begin
    if (reset)
        count <= 8'b00000000;
    else if (up_down)
        count <= count + 1;
    else
        count <= count - 1;
end

endmodule
